const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
if(input.length===0)process.exit(0);
let pos=0;
const T=parseInt(input[pos++],10);
let outputs=[];
for(let tc=0;tc<T;tc++){
  const n=parseInt(input[pos++],10);
  const total=n*n;
  let line=[];
  for(let i=1;i<=total;i++) line.push(i);
  outputs.push(line.join(' '));
}
process.stdout.write(outputs.join('\n'));
